#include<bits/stdc++.h>
using namespace std;
int a[50005],b[50005];
int main()
{
	int n;
	cin>>n;
	for(int i=1;i<=n;i++)cin>>a[i];
	for(int i=1;i<=n;i++)cin>>b[i];
	sort(a+1,a+n+1);
	sort(b+1,b+n+1);	
	int cnt=0; 
	for(int l=1,r=1;r<=n&&l<=n;l++){
		if(a[l]>b[r]){
			cnt++;
			r++;
		}
	}
	cout<<cnt;
}
